const state = {
  users: new Map(),
  sockets: new Map(),
  lobbies: new Map(),
  highscores: [],
  accountTotals: new Map()
};

function shuffle(arr) {
  const copy = [...arr];
  for (let i = copy.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [copy[i], copy[j]] = [copy[j], copy[i]];
  }
  return copy;
}

function serializeUser(user) {
  return { userId: user.userId, name: user.name, friends: user.friends, online: user.online };
}

function emitOnlineCount() {
  const onlineCount = [...state.users.values()].filter(u => u.online).length;
  io.emit("online_count", { onlineCount });
}

function createPlayerState() {
  return {
    moosDollar: 0,
    answered: false,
    answer: null,
    answerAt: null,
    jokers: { hint: true, fifty: true, skip: true }
  };
}

function pickUniqueQuestions(count) {
  return shuffle(QUESTION_BANK).slice(0, count);
}

function createLobby(hostUserId, invitedUserIds = []) {
  const lobbyId = uuidv4();
  const invited = invitedUserIds.map(userId => ({ userId, status: "pending" }));
  const questionOrder = pickUniqueQuestions(6);
  const lobby = {
    lobbyId,
    hostUserId,
    invited,
    acceptedUserIds: [hostUserId],
    declinedUserIds: [],
    status: "waiting",
    firstResponseAt: null,
    waitTimer: null,
    createdAt: Date.now(),
    game: {
      currentQuestionIndex: 0,
      questionOrder,
      usedQuestionIds: questionOrder.map(q => q.id),
      playerStates: { [hostUserId]: createPlayerState() },
      phase: "lobby",
      roundEndsAt: null,
      roundTimer: null
    }
  };
  state.lobbies.set(lobbyId, lobby);
  return lobby;
}

function currentQuestion(lobby) {
  return lobby.game.questionOrder[lobby.game.currentQuestionIndex] || null;
}

function publicScoreboard(lobby) {
  return lobby.acceptedUserIds.map(uid => ({
    userId: uid,
    name: state.users.get(uid)?.name || "Spieler",
    moosDollar: lobby.game.playerStates[uid]?.moosDollar || 0
  }));
}

function participantsOfLobby(lobby) {
  return new Set([lobby.hostUserId, ...lobby.invited.map(i => i.userId)]);
}

function emitLobby(lobby) {
  const safeLobby = {
    ...lobby,
    game: {
      ...lobby.game,
      usedQuestionIds: lobby.game.usedQuestionIds
    }
  };
  for (const userId of participantsOfLobby(lobby)) {
    const user = state.users.get(userId);
    if (user?.socketId) io.to(user.socketId).emit("lobby_update", safeLobby);
  }
}

function scheduleStartWindow(lobby) {
  if (lobby.waitTimer) return;
  lobby.waitTimer = setTimeout(() => startLobby(lobby), 15000);
}

function maybeStartLobby(lobby) {
  const allResponded = lobby.invited.every(i => i.status !== "pending");
  if (allResponded) startLobby(lobby);
}

function privateQuestionPayload(lobby, userId) {
  const q = currentQuestion(lobby);
  const ps = lobby.game.playerStates[userId];
  return {
    lobbyId: lobby.lobbyId,
    questionIndex: lobby.game.currentQuestionIndex,
    totalQuestions: lobby.game.questionOrder.length,
    roundEndsAt: lobby.game.roundEndsAt,
    question: {
      id: q.id,
      topic: q.topic,
      question: q.question,
      choices: q.choices
    },
    scoreboard: publicScoreboard(lobby),
    jokers: {
      hint: ps?.jokers?.hint || false,
      fifty: ps?.jokers?.fifty || false,
      skip: ps?.jokers?.skip || false
    }
  };
}

function emitQuestion(lobby) {
  const q = currentQuestion(lobby);
  if (!q) return endGame(lobby);
  lobby.game.phase = "question";
  lobby.game.roundEndsAt = Date.now() + ROUND_SECONDS * 1000;
  if (lobby.game.roundTimer) clearTimeout(lobby.game.roundTimer);
  lobby.game.roundTimer = setTimeout(() => finalizeRound(lobby), ROUND_SECONDS * 1000);

  for (const uid of lobby.acceptedUserIds) {
    const user = state.users.get(uid);
    if (user?.socketId) io.to(user.socketId).emit("game_question", privateQuestionPayload(lobby, uid));
  }
}

function startLobby(lobby) {
  if (lobby.status === "started") return;
  lobby.status = "started";
  if (lobby.waitTimer) clearTimeout(lobby.waitTimer);
  lobby.waitTimer = null;
  for (const uid of lobby.acceptedUserIds) {
    if (!lobby.game.playerStates[uid]) lobby.game.playerStates[uid] = createPlayerState();
  }
  emitLobby(lobby);
  emitQuestion(lobby);
}

function resetRoundFlags(lobby) {
  for (const uid of lobby.acceptedUserIds) {
    const ps = lobby.game.playerStates[uid];
    ps.answered = false;
    ps.answer = null;
    ps.answerAt = null;
  }
}

function finalizeRound(lobby) {
  if (lobby.game.phase !== "question") return;
  const q = currentQuestion(lobby);
  for (const uid of lobby.acceptedUserIds) {
    const ps = lobby.game.playerStates[uid];
    const correct = ps.answer === q.answer;
    if (correct) {
      const msLeft = Math.max(0, lobby.game.roundEndsAt - (ps.answerAt || lobby.game.roundEndsAt));
      const secLeft = Math.floor(msLeft / 1000);
      ps.moosDollar += 100 + (secLeft * 10);
    }
  }
  lobby.game.currentQuestionIndex += 1;
  lobby.game.phase = "round_result";
  if (lobby.game.roundTimer) clearTimeout(lobby.game.roundTimer);
  lobby.game.roundTimer = null;

  for (const uid of lobby.acceptedUserIds) {
    const user = state.users.get(uid);
    if (user?.socketId) {
      io.to(user.socketId).emit("round_result", {
        lobbyId: lobby.lobbyId,
        correctAnswer: q.answer,
        scoreboard: publicScoreboard(lobby)
      });
    }
  }

  resetRoundFlags(lobby);

  if (lobby.game.currentQuestionIndex >= lobby.game.questionOrder.length) {
    setTimeout(() => endGame(lobby), 1200);
  } else {
    setTimeout(() => emitQuestion(lobby), 1200);
  }
}

function maybeFinalizeRound(lobby) {
  const everybodyAnswered = lobby.acceptedUserIds.every(uid => lobby.game.playerStates[uid]?.answered);
  if (everybodyAnswered) finalizeRound(lobby);
}

function updateAccountTotals(results) {
  for (const r of results) {
    const existing = state.accountTotals.get(r.userId) || {
      userId: r.userId,
      name: r.name,
      totalMoosDollar: 0
    };
    existing.name = r.name;
    existing.totalMoosDollar += r.moosDollar;
    state.accountTotals.set(r.userId, existing);
  }
}

function sortedAccountTotals() {
  return [...state.accountTotals.values()].sort((a,b)=>b.totalMoosDollar-a.totalMoosDollar);
}

function endGame(lobby) {
  lobby.game.phase = "finished";
  const results = publicScoreboard(lobby).sort((a,b)=>b.moosDollar-a.moosDollar);

  state.highscores.push(...results.map(r => ({
    userId:r.userId,
    name:r.name,
    moosDollar:r.moosDollar,
    createdAt:Date.now()
  })));
  state.highscores.sort((a,b)=>b.moosDollar-a.moosDollar);
  state.highscores = state.highscores.slice(0, 50);

  updateAccountTotals(results);

  for (const uid of lobby.acceptedUserIds) {
    const user = state.users.get(uid);
    if (user?.socketId) io.to(user.socketId).emit("game_finished", {
      lobbyId:lobby.lobbyId,
      results,
      accountHighscores: sortedAccountTotals()
    });
  }

  io.emit("highscores_updated", state.highscores);
  io.emit("account_highscores_updated", sortedAccountTotals());
}

app.get("/health", (_req, res) => res.json({ ok: true }));
app.get("/highscores", (_req, res) => res.json(state.highscores));
app.get("/account-highscores", (_req, res) => res.json(sortedAccountTotals()));
app.get("/questions/meta", (_req, res) => {
  const counts = QUESTION_BANK.reduce((acc, q) => {
    acc[q.topic] = (acc[q.topic] || 0) + 1;
    return acc;
  }, {});
  res.json(counts);
});

app.post("/highscores/reset", (req, res) => {
  const { code } = req.body;
  if (!["0207","0809","1911"].includes(code)) return res.status(403).json({ error:"Invalid admin code" });
  state.highscores = [];
  state.accountTotals = new Map();
  io.emit("highscores_updated", state.highscores);
  io.emit("account_highscores_updated", []);
  res.json({ ok:true });
});

io.on("connection", (socket) => {
  socket.on("register_user", ({ name }) => {
    const userId = uuidv4();
    const user = { userId, name: name || "Spieler", socketId: socket.id, friends: [], online: true };
    state.users.set(userId, user);
    state.sockets.set(socket.id, userId);
    socket.emit("registered", serializeUser(user));
    socket.emit("account_highscores_updated", sortedAccountTotals());
    emitOnlineCount();
  });

  socket.on("add_friend", ({ userId, friendUserId }) => {
    const user = state.users.get(userId);
    const friend = state.users.get(friendUserId);
    if (!user || !friend) return;
    if (!user.friends.includes(friendUserId)) user.friends.push(friendUserId);
    if (!friend.friends.includes(userId)) friend.friends.push(userId);
    socket.emit("profile_updated", serializeUser(user));
    if (friend.socketId) io.to(friend.socketId).emit("profile_updated", serializeUser(friend));
  });

  socket.on("invite_players", ({ hostUserId, invitedUserIds }) => {
    const host = state.users.get(hostUserId);
    if (!host) return;
    const lobby = createLobby(hostUserId, invitedUserIds || []);
    emitLobby(lobby);
    for (const invited of lobby.invited) {
      const invitedUser = state.users.get(invited.userId);
      if (invitedUser?.socketId) {
        io.to(invitedUser.socketId).emit("invitation_received", {
          lobbyId: lobby.lobbyId,
          fromUserId: host.userId,
          fromName: host.name
        });
      }
    }
  });

  socket.on("respond_invitation", ({ userId, lobbyId, response }) => {
    const lobby = state.lobbies.get(lobbyId);
    if (!lobby || lobby.status !== "waiting") return;
    const invited = lobby.invited.find(i => i.userId === userId);
    if (!invited || invited.status !== "pending") return;

    invited.status = response === "accept" ? "accepted" : "declined";
    if (response === "accept") {
      lobby.acceptedUserIds.push(userId);
      lobby.game.playerStates[userId] = createPlayerState();
    } else {
      lobby.declinedUserIds.push(userId);
    }

    if (!lobby.firstResponseAt) {
      lobby.firstResponseAt = Date.now();
      scheduleStartWindow(lobby);
    }

    emitLobby(lobby);
    maybeStartLobby(lobby);
  });

  socket.on("use_joker", ({ userId, lobbyId, type }) => {
    const lobby = state.lobbies.get(lobbyId);
    if (!lobby || lobby.game.phase !== "question") return;
    const ps = lobby.game.playerStates[userId];
    if (!ps || !ps.jokers[type]) return;

    ps.jokers[type] = false;
    const q = currentQuestion(lobby);
    const user = state.users.get(userId);
    if (!user?.socketId) return;

    if (type === "hint") {
      io.to(user.socketId).emit("joker_result", { type, hint: q.hint, jokers: ps.jokers });
    } else if (type === "fifty") {
      const wrong = [0,1,2,3].filter(i => i !== q.answer);
      const removed = shuffle(wrong).slice(0,2);
      io.to(user.socketId).emit("joker_result", { type, removed, jokers: ps.jokers });
    } else if (type === "skip") {
      ps.answered = true;
      ps.answer = -1;
      ps.answerAt = Date.now();
      io.to(user.socketId).emit("joker_result", { type, jokers: ps.jokers });
      maybeFinalizeRound(lobby);
      return;
    }
    io.to(user.socketId).emit("game_question", privateQuestionPayload(lobby, userId));
  });

  socket.on("submit_answer", ({ userId, lobbyId, answer }) => {
    const lobby = state.lobbies.get(lobbyId);
    if (!lobby || lobby.game.phase !== "question") return;
    if (!lobby.acceptedUserIds.includes(userId)) return;
    const ps = lobby.game.playerStates[userId];
    if (!ps || ps.answered) return;
    ps.answered = true;
    ps.answer = answer;
    ps.answerAt = Date.now();
    maybeFinalizeRound(lobby);
  });

  socket.on("disconnect", () => {
    const userId = state.sockets.get(socket.id);
    if (!userId) return;
    const user = state.users.get(userId);
    if (user) {
      user.online = false;
      user.socketId = null;
    }
    state.sockets.delete(socket.id);
    emitOnlineCount();
  });
});

server.listen(PORT, () => {
  console.log(`Moos IQ backend v1.2 merged running on port ${PORT}`);
});
